// src/components/auth/FingerprintAuth.js
import React, { useState, useEffect } from 'react';
import { useSensor } from '../../hooks/useSensor';
import './FingerprintAuth.css';

const FingerprintAuth = ({ onSuccess, onError }) => {
    const [status, setStatus] = useState('idle');
    const [message, setMessage] = useState('');
    const { 
        status: sensorStatus, 
        loading, 
        scanFingerprint,
        enrollFingerprint,
        isSupported 
    } = useSensor();

    // Log sensor status on mount and when it changes
    useEffect(() => {
        console.log('FingerprintAuth - Sensor status:', sensorStatus);
        
        if (!sensorStatus.connected) {
            setStatus('disconnected');
            setMessage('⚠️ Fingerprint sensor not connected. Please connect from login page first.');
        } else {
            setStatus('ready');
            setMessage('Sensor ready. Click "Scan Fingerprint" to begin.');
        }
    }, [sensorStatus]);

    const handleScan = async () => {
        console.log('Starting fingerprint scan...');
        
        if (!sensorStatus.connected) {
            setStatus('error');
            setMessage('⚠️ Fingerprint sensor not connected');
            if (onError) onError(new Error('Sensor not connected'));
            return;
        }
        
        setStatus('scanning');
        setMessage('Please place your finger on the sensor...');
        
        try {
            const result = await scanFingerprint();
            console.log('Scan result:', result);
            
            if (result.success) {
                setStatus('success');
                setMessage(`✅ Fingerprint recognized! User ID: ${result.userId}`);
                if (onSuccess) onSuccess(result);
            }
        } catch (error) {
            console.error('Scan error:', error);
            setStatus('error');
            setMessage(`❌ Scan failed: ${error.message}`);
            if (onError) onError(error);
        }
    };

    const handleEnroll = async () => {
        console.log('Starting fingerprint enrollment...');
        
        if (!sensorStatus.connected) {
            setStatus('error');
            setMessage('⚠️ Fingerprint sensor not connected');
            if (onError) onError(new Error('Sensor not connected'));
            return;
        }
        
        setStatus('enrolling');
        setMessage('Please follow the enrollment instructions...');
        
        try {
            const result = await enrollFingerprint();
            console.log('Enrollment result:', result);
            
            if (result.success) {
                setStatus('success');
                setMessage(`✅ Fingerprint enrolled! ID: ${result.userId}`);
            }
        } catch (error) {
            console.error('Enrollment error:', error);
            setStatus('error');
            setMessage(`❌ Enrollment failed: ${error.message}`);
            if (onError) onError(error);
        }
    };

    const handleDebugScan = async () => {
        console.log('🐛 Debug scan started...');
        
        if (!sensorStatus.connected) {
            console.log('❌ Sensor not connected');
            setMessage('⚠️ Sensor not connected. Please connect first.');
            return;
        }
        
        setMessage('🐛 Debug mode: Sending SCAN command...');
        
        try {
            // Send raw SCAN command and log everything
            const result = await scanFingerprint();
            console.log('🐛 Debug result:', result);
            setMessage(`🐛 Debug: Scan completed. Success: ${result.success}, User ID: ${result.userId}`);
        } catch (error) {
            console.error('🐛 Debug error:', error);
            setMessage(`🐛 Debug error: ${error.message}`);
        }
    };

    if (!isSupported) {
        return (
            <div className="auth-container">
                <div className="error-message">
                    ⚠️ Web Serial not supported. Please use Chrome or Edge.
                </div>
            </div>
        );
    }

    return (
        <div className="auth-container">
            <div className="fingerprint-card">
                <div className="fingerprint-animation">
                    <div className={`fingerprint-icon ${status}`}>
                        <svg viewBox="0 0 24 24">
                            <path d="M12 2C8.13 2 5 5.13 5 9v6c0 3.87 3.13 7 7 7s7-3.13 7-7V9c0-3.87-3.13-7-7-7z"/>
                        </svg>
                    </div>
                </div>

                <div className="status-section">
                    {!sensorStatus.connected ? (
                        <div className="sensor-not-connected">
                            <p>⚠️ Fingerprint sensor not connected</p>
                            <p className="hint">Please connect the sensor from the login page first</p>
                        </div>
                    ) : (
                        <>
                            <div className="sensor-badge">
                                <span className="sensor-dot"></span>
                                Sensor Ready
                            </div>
                            <div className="button-group">
                                <button 
                                    className="btn-primary"
                                    onClick={handleScan}
                                    disabled={loading}
                                >
                                    {loading ? 'Scanning...' : '🔍 Scan Fingerprint'}
                                </button>
                                <button 
                                    className="btn-secondary"
                                    onClick={handleEnroll}
                                    disabled={loading}
                                >
                                    {loading ? 'Enrolling...' : '📝 Enroll Fingerprint'}
                                </button>
                                <button 
                                    className="btn-debug"
                                    onClick={handleDebugScan}
                                    disabled={loading}
                                >
                                    🐛 Debug Scan
                                </button>
                            </div>
                        </>
                    )}
                </div>

                {message && (
                    <div className={`status-message ${status}`}>
                        {message}
                    </div>
                )}
            </div>
        </div>
    );
};

export default FingerprintAuth;
